sql:
SELECT facility_name
FROM admission_facilities
WHERE capacity > 400;

SELECT gender, COUNT(*) AS defendant_count
FROM defendants
GROUP BY gender;

external_knowledge:
- 'VTL 0306' is a specific traffic violation charge; 
- 'Arrest for VTL 0306' is the reason for the defendant's admission; 
- 'Released on Bail' is a release status indicating that the defendant was released after paying bail.

sql:
SELECT MAX(admission_date)
  FROM admission_records
  WHERE defendant_id = 1;

SELECT COUNT(defendant_id) AS charge_count
FROM charge_records
WHERE charge_id = 1;

SELECT admission_date
FROM admission_records
WHERE admission_date LIKE '2019%';

SELECT facility_name, location
FROM admission_facilities
WHERE facility_id = 0;

SELECT COUNT(defendant_id) AS eligible_defendants_count
FROM bail_records
WHERE bail_status_id = 1;
